class Solution {
    public boolean isRationalEqual(String s, String t) {
        return decimalToDecimal(s).equals(decimalToDecimal(t));
    }
    private double decimalToDecimal(String s) {
        int integerPartEnd = s.indexOf('.');
        if (integerPartEnd == -1) {
            return Double.parseDouble(s);
        }
        String integerPart = s.substring(0, integerPartEnd);
        String nonRepeatingPart = s.substring(integerPartEnd + 1, s.indexOf('('));
        String repeatingPart = s.substring(s.indexOf('(') + 1, s.indexOf(')'));
        double decimal = Double.parseDouble(integerPart + "." + nonRepeatingPart);
        double factor = Math.pow(10, repeatingPart.length());
        return decimal + Double.parseDouble(repeatingPart) / factor;
    }
}
